def main() -> None:
    text = PATH.read_text(encoding="utf-8")
    if I8_TABLE_OLD not in text:
        raise SystemExit("I.8 table block not found — already updated?")
    text = text.replace(I8_INTRO_OLD, I8_INTRO_NEW)
    text = text.replace(I8_TABLE_OLD, I8_TABLE_NEW)
    text = text.replace(FOOTER_OLD, FOOTER_NEW)
    text = text.replace(REF_DOCS_OLD, REF_DOCS_NEW)
    for old, new in CANVAS_LINKS:
        text = text.replace(old, new)
    text = text.replace("*Макет: см. [I.8](#i8-сводная-таблица-макетов-ui) и canvas в `canvases/`*", FOOTER_NEW)
    text = text.replace("Макет — **Тест-диалог внутреннего пользователя КЦ**.", "Макет — **Тест-диалог внутреннего пользователя КЦ** ([I.8](#i8-сводная-таблица-макетов-ui), II-KC).")
    # I.5 footer
    text = text.replace("*Макет: см. [I.8](#i8-сводная-таблица-макетов-ui) и canvas в `canvases/`*", FOOTER_NEW)
    reserved = text.count("зарезервировано")
    PATH.write_text(text, encoding="utf-8")
    print(f"Updated {PATH}")
    print(f"remaining 'зарезервировано' in mockup table context: {reserved}")
    print(f"Canvas names in I.8: {text.count('**Оболочка AI Hub**')}")


if __name__ == "__main__":
    main()
